import openmc
import os
from simulation_config import SimulationConfig
import numpy as np


def get_cell_center(cell):
    bb = cell.bounding_box

    x0 = 0.5 * (bb.lower_left[0] + bb.upper_right[0])
    y0 = 0.5 * (bb.lower_left[1] + bb.upper_right[1])

    return x0, y0


