    def make_reaction_filter(xs_dir, library, nuclide, MT, temperature='294K'):
        """
        Create an EnergyFunctionFilter for a given nuclide and MT reaction.

        Parameters
        ----------
        xs_dir : str
            Path to directory containing HDF5 xsdata files.
        library : str
            Nuclear data library prefix (e.g. 'FENDL-3.1d', 'ENDFB-7.1').
        nuclide : str
            Target nuclide, e.g. 'U235', 'Au197'.
        MT : int
            ENDF MT reaction number, e.g. 102=(n,gamma), 18=fission.
        temperature : str
            Temperature key inside the HDF5 file, default '300K'.

        Returns
        -------
        openmc.EnergyFunctionFilter
            Filter that multiplies tally scores by σ(E) for the given nuclide.
        """

        # HDF5 filename
        xs_filename = os.path.join(xs_dir, f"{library}{nuclide}.h5")
        if not os.path.exists(xs_filename):
            raise FileNotFoundError(f"Cross-section file not found: {xs_filename}")

        # Load microscopic cross section data
        xs_data = openmc.data.IncidentNeutron.from_hdf5(xs_filename)

        # Extract reaction
        if MT not in xs_data.reactions:
            avail = list(xs_data.reactions.keys())
            raise ValueError(f"MT={MT} not available for {nuclide}. "
                            f"Available MTs: {avail}")

        reaction = xs_data.reactions[MT]

        # Select tabulated cross-section at given temperature
        tab1d = reaction.xs[temperature]

        # Build energy-function filter from cross-section table
        energy_filter = openmc.EnergyFunctionFilter.from_tabulated1d(tab1d)

        return energy_filter


    xs_dir = "/home/faticen/cross_sections/"
    fission_filter = make_reaction_filter(xs_dir,  "endfb-vii.1-hdf5/neutron/", "Au197", 102)



    def make_rod_cyl_mesh_F14(cell, x0, y0, r_max, n_r, z_min, z_max, n_z):
        """
        Create a cylindrical mesh tally centered on a fuel rod or air rod.

        Parameters:
            cell : openmc.Cell
            x0, y0 : float  rod center position
            r_max : float   maximum radius of mesh
            n_r   : int     number of radial bins
            z_min, z_max : float  axial bounds (absolute Z in geometry)
            n_z   : int     number of axial bins
        """

        mesh = openmc.CylindricalMesh(
            r_grid=np.linspace(0.0, r_max, n_r+1),
            z_grid=np.linspace(z_min, z_max, n_z+1),
            phi_grid=[0, 2*np.pi],       # full azimuthal coverage
            origin=[x0, y0, 0.0],        # << THIS IS CRITICAL
            name=f"mesh_cell_{cell.id}"
        )
        au_capture_filter = make_reaction_filter(xs_dir, "endfb-vii.1-hdf5/neutron/", "Au197", 102)
        tally = openmc.Tally(name=f"F14_tally_cell_{cell.id}")
        tally.filters = [
            openmc.CellFilter([cell.id]),
            openmc.MeshFilter(mesh),
            au_capture_filter
        ]
        tally.scores = ["flux"]  # equivalent to MCNP F4

        return tally

    def make_rod_cyl_mesh_F4(cell, x0, y0, r_max, n_r, z_min, z_max, n_z):
        """
        Create a cylindrical mesh tally centered on a fuel rod or air rod.

        Parameters:
            cell : openmc.Cell
            x0, y0 : float  rod center position
            r_max : float   maximum radius of mesh
            n_r   : int     number of radial bins
            z_min, z_max : float  axial bounds (absolute Z in geometry)
            n_z   : int     number of axial bins
        """

        mesh = openmc.CylindricalMesh(
            r_grid=np.linspace(0.0, r_max, n_r+1),
            z_grid=np.linspace(z_min, z_max, n_z+1),
            phi_grid=[0, 2*np.pi],       # full azimuthal coverage
            origin=[x0, y0, 0.0],        # << THIS IS CRITICAL
            name=f"mesh_cell_{cell.id}"
        )

        tally = openmc.Tally(name=f"F4_tally_cell_{cell.id}")
        tally.filters = [
            openmc.CellFilter([cell.id]),
            openmc.MeshFilter(mesh),
        ]
        tally.scores = ["flux"]  # equivalent to MCNP F4

        return tally


    def make_rod_cyl_mesh_tally(
        cell, 
        assembly_id, 
        rod_id,
        x0, y0,
        r_max, n_r,
        z_min, z_max, n_z,
        score,
        name_prefix
        ):

        """
        Create a cylindrical mesh tally around a single rod.

        Parameters
        ----------
        cell : openmc.Cell or int
            Fuel rod cell (or its ID).
        x0, y0 : float
            Rod center in Cartesian coordinates [cm].
        r_max : float
            Maximum radial distance of mesh [cm].
        n_r : int
            Number of radial bins.
        z_min, z_max : float
            Axial bounds [cm] in geometry coordinates (relative to origin z).
        n_z : int
            Number of axial bins.
        score : str
            OpenMC score, e.g. "kappa-fission" or "heating".
        name_prefix : str
            Prefix for tally and mesh names.
        """

        mesh = openmc.CylindricalMesh(
            r_grid=np.linspace(0.0, r_max, n_r + 1),
            z_grid=np.linspace(z_min, z_max, n_z + 1),
            phi_grid=[0.0, 2.0 * np.pi],   # full azimuth
            origin=[x0, y0, 0.0],          # rod axis passes through this point
            name=f"{name_prefix}_mesh_cell_a{assembly_id}_p{rod_id}"
        )

        tally = openmc.Tally(name=f"{name_prefix}_tally_cell_a{assembly_id}_p{rod_id}")
        tally.filters = [
           # openmc.CellFilter([cell_id]),
            openmc.MeshFilter(mesh),
        ]
        tally.scores = [score]

        return tally


